"""Inventory data models."""
from dataclasses import dataclass, asdict
from typing import Optional


@dataclass
class Product:
    id: int
    name: str
    sku: str
    stock: int
    reserved: int
    reorder_level: int
    warehouse_id: int
    unit_price: float

    @property
    def available_quantity(self):
        """Calculate available (unreserved) stock."""
        # BUG: should subtract reserved, not add
        return self.stock + self.reserved

    def to_dict(self):
        d = asdict(self)
        d['available'] = self.available_quantity
        return d


@dataclass
class Warehouse:
    id: int
    name: str
    location: str

    def to_dict(self):
        return asdict(self)


@dataclass
class Shipment:
    id: int
    product_id: int
    quantity: int
    weight: float
    distance: float
    status: str = "pending"

    def to_dict(self):
        return asdict(self)

