# --- Pricing functions (should be extracted to pricing.py) ---

def unit_price_with_discount(unit_price, discount_percent):
    """Apply a percentage discount to unit price.
    Example: unit_price_with_discount(100, 10) should return 90.0
    """
    factor = 1 - discount_percent / 100
    return round(unit_price * factor, 2)


def bulk_discount(unit_price, quantity, threshold=10, discount_pct=5.0):
    """Calculate total price for a bulk order.
    If quantity >= threshold, apply discount_pct off each unit.
    Returns total price (unit * quantity).
    """
    if quantity >= threshold:
        effective = unit_price_with_discount(unit_price, discount_pct)
    else:
        effective = unit_price
    return round(effective * quantity, 2)


def shipping_cost(weight, distance, rate_per_kg_km=0.05):
    """Calculate shipping cost based on weight and distance.
    cost = weight * distance * rate_per_kg_km
    """
    return round(weight * distance * rate_per_kg_km, 2)


# --- Handler class ---

class InventoryHandler:
    def __init__(self, products: dict, warehouses: dict):
        self.products = products
        self.warehouses = warehouses

    def list_products(self, warehouse_id=None):
        """Return (products_list, 200)."""
        items = list(self.products.values())
        if warehouse_id is not None:
            items = [p for p in items if p.warehouse_id == warehouse_id]
        return [p.to_dict() for p in items], 200

    def get_product(self, product_id):
        """Return (product_dict, 200) or (error, 404)."""
        product = self.products.get(product_id)
        if product is None:
            return {"error": "Product not found"}, 404
        return product.to_dict(), 200

    def search_products(self, query):
        """Search products by name (case-insensitive substring)."""
        query_lower = query.lower()
        if not query_lower:
            return [], 200
        matches = [p for p in self.products.values()
                   if query_lower in p.name.lower()]
        return [p.to_dict() for p in matches], 200

    def check_reorder(self):
        """Return products that need reordering (available < reorder_level)."""
        # BUG: comparison is inverted — flags products ABOVE reorder level
        needs_reorder = [p for p in self.products.values()
                         if p.available_quantity > p.reorder_level]
        return [p.to_dict() for p in needs_reorder], 200

    def get_discounted_price(self, unit_price, discount_percent):
        """Get discounted unit price."""
        return unit_price_with_discount(unit_price, discount_percent)

    def get_bulk_total(self, unit_price, quantity):
        """Get bulk order total."""
        return bulk_discount(unit_price, quantity)

    def get_shipping_cost(self, weight, distance):
        """Get shipping cost."""
        return shipping_cost(weight, distance)

    def get_price_info(self, product_id, discount_pct=0, quantity=1):
        """Return (price_info_dict, 200) or (error, 404)."""
        product = self.products.get(product_id)
        if product is None:
            return {"error": "Product not found"}, 404
        unit = product.unit_price
        if discount_pct > 0:
            unit = self.get_discounted_price(unit, discount_pct)
        total = self.get_bulk_total(unit, quantity)
        return {
            "product_id": product_id,
            "unit_price": unit,
            "quantity": quantity,
            "total": total,
            "formatted_total": f"${total:.2f}",
        }, 200

